<div class="de">
<svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">Je Mehr Wiederholungen, Desto Stärker Sinkt das Risiko Relativ zur Erwarteten Rendite</text>
  <text x="20" y="48" fill="#71717a" font-size="12" font-family="sans-serif">Variationskoeffizient (Standardabw. ÷ Mittelwert) von Samuelsons Wette (Gewinn +200 $ / Verlust -100 $, je 50%)</text>
  <text x="20" y="86" fill="#d4d4d8" font-size="13.5" font-weight="700" font-family="sans-serif">N=1</text>
  <rect x="170" y="74" width="400" height="22" fill="#f59e0b" rx="3"/>
  <text x="580" y="90" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">3.00</text>
  <text x="20" y="134" fill="#d4d4d8" font-size="13.5" font-weight="700" font-family="sans-serif">N=5</text>
