  <text x="359" y="138" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">1.34</text>
  <text x="20" y="182" fill="#d4d4d8" font-size="13.5" font-weight="700" font-family="sans-serif">N=10</text>
  <rect x="170" y="170" width="126" height="22" fill="#f59e0b" rx="3"/>
  <text x="306" y="186" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">0.95</text>
  <text x="20" y="230" fill="#d4d4d8" font-size="13.5" font-weight="700" font-family="sans-serif">N=25</text>
  <rect x="170" y="218" width="80" height="22" fill="#f59e0b" rx="3"/>
